export interface CronSchedule {
  minutes: number[];
  hours: number[];
  daysOfMonth: number[];
  months: number[];
  daysOfWeek: number[];
  original: string;
}

export class CronParseError extends Error {
  constructor(message: string, public field?: string) {
    super(message);
    this.name = 'CronParseError';
  }
}

function parseField(field: string, min: number, max: number, fieldName: string): number[] {
  const results: number[] = [];

  if (field === '*') {
    for (let i = min; i <= max; i++) results.push(i);
    return results;
  }

  // Handle lists
  if (field.includes(',')) {
    const parts = field.split(',');
    for (const part of parts) {
      const values = parseField(part.trim(), min, max, fieldName);
      for (const v of values) {
        if (!results.includes(v)) results.push(v);
      }
    }
    results.sort((a, b) => a - b);
    return results;
  }

  // Handle range with step: N-M/S
  const rangeStepMatch = field.match(/^(\d+)-(\d+)\/(\d+)$/);
  if (rangeStepMatch) {
    const start = parseInt(rangeStepMatch[1], 10);
    const end = parseInt(rangeStepMatch[2], 10);
    const step = parseInt(rangeStepMatch[3], 10);

    if (start < min || start > max) throw new CronParseError(`Value ${start} out of range [${min}-${max}] in field "${fieldName}"`, fieldName);
    if (end < min || end > max) throw new CronParseError(`Value ${end} out of range [${min}-${max}] in field "${fieldName}"`, fieldName);
    if (start > end) throw new CronParseError(`Invalid range ${start}-${end} in field "${fieldName}"`, fieldName);
    if (step <= 0) throw new CronParseError(`Invalid step ${step} in field "${fieldName}"`, fieldName);

    for (let i = start; i <= end; i += step) results.push(i);
    return results;
  }

  // Handle step with wildcard: */N
  const wildcardStepMatch = field.match(/^\*\/(\d+)$/);
  if (wildcardStepMatch) {
    const step = parseInt(wildcardStepMatch[1], 10);
    if (step <= 0) throw new CronParseError(`Invalid step ${step} in field "${fieldName}"`, fieldName);
    for (let i = min; i <= max; i += step) results.push(i);
    return results;
  }

  // Handle range: N-M
  const rangeMatch = field.match(/^(\d+)-(\d+)$/);
  if (rangeMatch) {
    const start = parseInt(rangeMatch[1], 10);
    const end = parseInt(rangeMatch[2], 10);

    if (start < min || start > max) throw new CronParseError(`Value ${start} out of range [${min}-${max}] in field "${fieldName}"`, fieldName);
    if (end < min || end > max) throw new CronParseError(`Value ${end} out of range [${min}-${max}] in field "${fieldName}"`, fieldName);
    if (start > end) throw new CronParseError(`Invalid range ${start}-${end} in field "${fieldName}"`, fieldName);

    for (let i = start; i <= end; i++) results.push(i);
    return results;
  }

  // Handle single value
  const singleMatch = field.match(/^(\d+)$/);
  if (singleMatch) {
    const val = parseInt(singleMatch[1], 10);
    if (val < min || val > max) throw new CronParseError(`Value ${val} out of range [${min}-${max}] in field "${fieldName}"`, fieldName);
    results.push(val);
    return results;
  }

  throw new CronParseError(`Invalid syntax "${field}" in field "${fieldName}"`, fieldName);
}

export function parseCron(expression: string): CronSchedule {
  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new CronParseError(`Expected 5 fields, got ${fields.length}`);
  }

  const [minuteField, hourField, domField, monthField, dowField] = fields;

  const minutes = parseField(minuteField, 0, 59, 'minute');
  const hours = parseField(hourField, 0, 23, 'hour');
  const daysOfMonth = parseField(domField, 1, 31, 'day-of-month');
  const months = parseField(monthField, 1, 12, 'month');
  const daysOfWeek = parseField(dowField, 0, 6, 'day-of-week');

  return {
    minutes,
    hours,
    daysOfMonth,
    months,
    daysOfWeek,
    original: expression,
  };
}

export class RateLimiter {
  private tokens: number;
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private lastRefill: number;

  constructor(maxTokens: number, refillRate: number) {
    this.maxTokens = maxTokens;
    this.tokens = maxTokens;
    this.refillRate = refillRate;
    this.lastRefill = Date.now();
  }

  tryConsume(): boolean {
    this.refill();

    if (this.tokens >= 1) {
      this.tokens -= 1;
      return true;
    }
    return false;
  }

  getTokens(): number {
    this.refill();
    return this.tokens;
  }

  reset(): void {
    this.tokens = this.maxTokens;
    this.lastRefill = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefill;

    const newTokens = (elapsed * this.refillRate) / 1000;

    this.tokens = Math.min(this.maxTokens, this.tokens + newTokens);

    this.lastRefill = now;
  }
}
